WITH FREIGHTLISTS AS ( SELECT DISTINCT VEDISK, VEANR1 FROM NPLDATV6 .PVERSNDL9 WHERE VEKONZ CONCAT VEFIRM IN ('610010') AND VEAJH * 1000000 + VEAJA * 10000 + VEAMO * 100 + VEATA >= 20260504 AND VEAJH * 1000000 + VEAJA * 10000 + VEAMO * 100 + VEATA <= 20260504 ) SELECT TPKONZ AS KONZ,TPFIRM AS FIRM, CONCAT(TPVSST,'') SST, TPEJH JH, TPEJA JA, TPEMO MO, TPETA TA, TRIM(TPWENR) REFERENZ, '' FREIGHTLIST, TRIM(TPLIEF) LIEFERANT_PO, TRIM(TPLSNR) LIEFERANT_STO, '' EMPFAENGER, '' ORT, '' LAND, 'WE' VERSANDART, '' AKBHF, '' LADEMITTELART, TRIM(TPLM) LADEMITTELTYP, TRIM(TPTOUR) TOUR, '' AS KFZ, COUNT(*) ANZAHL FROM NPLDATV6.PHISTTP WHERE TPKONZ = '610' and TPFIRM = '010' and TPRCDE = 'OK' AND TPTTYP = 'E' AND TPVSST IN ('111','112','113', '114', '123') AND TPEJH * 1000000 + TPEJA * 10000 + TPEMO * 100 + TPETA >= 20260504 and TPEJH * 1000000 + TPEJA * 10000 + TPEMO * 100 + TPETA <= 20260504 GROUP BY TPKONZ,TPFIRM,TPVSST, TPEJH, TPEJA, TPEMO, TPETA, TPWENR, TPLIEF, TPLSNR, TPLM, TPTOUR UNION ALL SELECT TPKONZ AS KONZ, TPFIRM AS FIRM, CONCAT(TPVSST,'') SST, TPEJH JH, TPEJA JA, TPEMO MO, TPETA TA, TRIM(TPWENR) REFERENZ, '' FREIGHTLIST,TRIM(TPLIEF) LIEFERANT_PO, TRIM(TPLSNR) LIEFERANT_STO, '' EMPFAENGER, '' ORT, '' LAND, 'WE' VERSANDART, '' AKBHF, '' LADEMITTELART, TRIM(TPLM) LADEMITTELTYP, TRIM(TPTOUR) TOUR, '' AS KFZ, COUNT(*) ANZAHL FROM NPLDATV6 .PHISTTPL1 WHERE ( TPKONZ ='610' AND TPFIRM='050' OR TPKONZ ='610' AND TPFIRM='060' OR TPKONZ ='610' AND TPFIRM='070' OR TPKONZ ='610' AND TPFIRM='080' OR TPKONZ ='610' AND TPFIRM='090' OR TPKONZ ='610' AND TPFIRM='100' OR TPKONZ ='600' AND TPFIRM='010' OR TPKONZ ='610' AND TPFIRM='110' OR TPKONZ ='610' AND TPFIRM='120' OR TPKONZ ='600' AND TPFIRM='250' ) AND TPRCDE = 'OK' AND TPTTYP = 'E' AND TPEJH * 1000000 + TPEJA * 10000 + TPEMO * 100 + TPETA >= 20260504 AND TPEJH * 1000000+ TPEJA * 10000+ TPEMO * 100+ TPETA <= 20260504 GROUP BY TPKONZ,TPFIRM,TPVSST, TPEJH, TPEJA, TPEMO, TPETA, TPWENR, TPLIEF, TPLSNR, TPLM, TPTOUR UNION ALL SELECT AKKONZ AS KONZ, AKFIRM AS FIRM, '' SST, AKLJH JH, AKLJA JA, AKLMO MO, AKLTA TA, TRIM(AKANR1) REFERENZ, '' FREIGHTLIST, '' LIEFERANT_PO, '' LIEFERANT_STO, TRIM(AKAN1) EMPFAENGER, TRIM(AKLORT) ORT, TRIM(AKLAKZ) LAND, TRIM(AKVART) VERSANDART, AKBHF, '1' LADEMITTELART, TRIM(PKPTYP) LADEMITTELTYP, TRIM(AKTOUR) TOUR, '' AS KFZ, COUNT(*) ANZAHL FROM NPLDATV6 .PSAVEAKK16 JOIN NPLDATV6 .PPAKET ON (AKKONZ, AKFIRM, AKAPN )=(PKKONZ, PKFIRM, PKAPN) AND PKIDEN='' AND PKVLKZ='9' WHERE AKKONZ CONCAT AKFIRM IN ('610060','600010','600250','610050','610070','610080','610090','610100','610110','610120') AND AKLJH > 0 AND AKVLKZ IN ('9','8') AND AKVART NOT IN ('GLS','PROD', 'DPD') AND AKLJH * 1000000 + AKLJA * 10000 + AKLMO * 100 + AKLTA >= 20260504 AND AKLJH * 1000000 +AKLJA * 10000 +AKLMO * 100 +AKLTA <= 20260504 GROUP BY AKKONZ ,AKFIRM , AKLJH, AKLJA, AKLMO, AKLTA, AKANR1, AKLORT, AKLAKZ, AKAN1, AKVART, AKBHF, PKPTYP, AKTOUR UNION ALL SELECT AKKONZ AS KONZ, AKFIRM AS FIRM, '' SST, AKLJH JH, AKLJA JA, AKLMO MO, AKLTA TA, TRIM(AKANR1) REFERENZ, VEDISK FREIGHTLIST, '' LIEFERANT_PO, '' LIEFERANT_STO, TRIM(AKAN1) EMPFAENGER, TRIM(AKLORT) ORT, TRIM(AKLAKZ) LAND, TRIM(AKVART) VERSANDART, AKBHF, '1' LADEMITTELART, TRIM(PKPTYP) LADEMITTELTYP, TRIM(AKTOUR) TOUR, '' AS KFZ, COUNT(*) ANZAHL FROM NPLDATV6.PSAVEAKK16 JOIN NPLDATV6.PPAKET ON (AKKONZ, AKFIRM, AKAPN )=(PKKONZ, PKFIRM, PKAPN) AND PKIDEN='' AND PKVLKZ='9' JOIN FREIGHTLISTS ON AKANR1=VEANR1 WHERE AKKONZ CONCAT AKFIRM IN ('610010') AND AKLJH > 0 AND AKVLKZ IN ('9','8') AND AKVART NOT IN ('GLS','PROD', 'DPD') AND AKLJH * 1000000 + AKLJA * 10000 + AKLMO * 100 + AKLTA >= 20260504 AND AKLJH * 1000000 +AKLJA * 10000 +AKLMO * 100 +AKLTA <= 20260504 GROUP BY AKKONZ ,AKFIRM , AKLJH, AKLJA, AKLMO, AKLTA, AKANR1, VEDISK,AKLORT, AKLAKZ, AKAN1, AKVART, AKBHF, PKPTYP, AKTOUR UNION ALL SELECT AKKONZ AS KONZ ,AKFIRM AS FIRM,'' SST, AKLJH JH, AKLJA JA, AKLMO MO, AKLTA TA, TRIM(AKANR1) REFERENZ,VEDISK FREIGHTLIST, '' LIEFERANT_PO, '' LIEFERANT_STO, TRIM(AKAN1) EMPFAENGER, TRIM(AKLORT) ORT, TRIM(AKLAKZ) LAND, TRIM(AKVART) VERSANDART, AKBHF, TRIM(VLVLMA) LADEMITTELART, TRIM(VLVLMT) LADEMITTELTYP, TRIM(AKTOUR) TOUR, '' AS KFZ, COUNT(*) ANZAHL FROM NPLDATV6 .PSAVEAKK16 JOIN NPLDATV6 .PVERSLM ON (AKKONZ, AKFIRM, AKAPN )=(VLKONZ, VLFIRM, VLAPN ) AND VLVLMA=2 JOIN FREIGHTLISTS ON AKANR1=VEANR1 WHERE AKKONZ = '610' and AKFIRM = '010' and AKLJH > 0 AND AKVLKZ IN ('9','8') AND AKVART NOT IN ('GLS','PROD', 'DPD') AND AKLJH * 1000000 + AKLJA * 10000 + AKLMO * 100 + AKLTA >= 20260504 and AKLJH * 1000000 + AKLJA * 10000 + AKLMO * 100 + AKLTA <= 20260504 GROUP BY AKKONZ,AKFIRM,AKLJH, AKLJA, AKLMO, AKLTA, AKANR1, VEDISK, AKLORT, AKLAKZ, AKAN1, AKVART, AKBHF, VLVLMA, VLVLMT, AKTOUR UNION ALL SELECT KONZ, FIRM, '999' SST, VKAJH JH, VKAJA JA, VKAMO MO, VKATA TA, '' REFERENZ, CONCAT(VKDISK,'') FREIGHTLIST, '' LIEFERANT_PO, '' LIEFERANT_STO, '' EMPFAENGER, '' ORT, '' LAND, VKVART VERSANDART, VKSPED AKBHF, CASE WHEN P.CATEGORY = 0 THEN '3' WHEN P.CATEGORY = 1 THEN '4' ELSE '?' END AS LADEMITTELART, HLM_ID LADEMITTELTYP, '' TOUR, VKKFZ AS KFZ, QTY ANZAHL FROM NOELIVV1.VERLADUNG_HLM_KOP K JOIN NOELIVV1.VERLADUNG_HLM_POS P ON (K.ID) = (P.KOP_ID) JOIN NPLDATV6.PVERKOP ON (K.KONZ, K.FIRM, K.DISK) = (VKKONZ, VKFIRM, VKDISK) WHERE K.KONZ = '610' AND K.FIRM = '010' AND VKAJH * 1000000 + VKAJA * 10000 + VKAMO * 100 + VKATA >= 20260504 AND VKAJH * 1000000 + VKAJA * 10000 + VKAMO * 100 + VKATA <= 20260504 and K.DISK > 0 UNION ALL SELECT AKKONZ AS KONZ, AKFIRM AS FIRM, '' SST, AKBJH JH, AKBJA JA, AKBMO MO, AKBTA TA, TRIM(AKANR1) REFERENZ, '' FREIGHTLIST, '' LIEFERANT_PO, '' LIEFERANT_STO, TRIM(AKAN1) EMPFAENGER, TRIM(AKLORT) ORT, TRIM(AKLAKZ) LAND, TRIM(AKVART) VERSANDART, AKBHF, '1' LADEMITTELART, TRIM(PKPTYP) LADEMITTELTYP, TRIM(AKTOUR) TOUR, '' AS KFZ, COUNT(*) ANZAHL FROM NPLDATV6.PSAVEAKK16 JOIN NPLDATV6.PPAKET ON (AKKONZ, AKFIRM, AKAPN )=(PKKONZ, PKFIRM, PKAPN) AND PKIDEN='' WHERE AKKONZ CONCAT AKFIRM IN ('610010') AND AKLUSR = '' AND AKVLKZ = '4' AND AKVART IN ('MOBU','MOBC') AND AKBJH * 1000000 + AKBJA * 10000 + AKBMO * 100 + AKBTA >= '20260504' AND AKBJH * 1000000 + AKBJA * 10000 + AKBMO * 100 + AKBTA <= '20260504' GROUP BY AKKONZ ,AKFIRM , AKBJH, AKBJA, AKBMO, AKBTA, AKANR1,AKLORT, AKLAKZ, AKAN1, AKVART, AKBHF, PKPTYP, AKTOUR ORDER BY KONZ, FIRM,JH, JA, MO, TA, VERSANDART, REFERENZ , LIEFERANT_PO, LIEFERANT_STO, EMPFAENGER, LADEMITTELART, LADEMITTELTYP, ANZAHL 
